import React, { useState } from 'react'
import { Link } from 'react-router-dom'
import AddDecoPage from './AddDecoPage'
import RoomInfo from './RoomInfo'



export default function EditRoom(props) {
  const [addPage, setAddPage] = useState(true)
  const [buttonText, setButtonText] = useState("Add item")

    let whatPageToShow=()=>{
      if(addPage){
        return <RoomInfo room={props.room} turnOnOrOff={props.turnOnOrOff}/>
      }
      else {
        return <AddDecoPage setAddPage={setAddPage}  addNewDeco={props.addNewDeco}/>
      }
    }
    let changeAddPage=()=>{
      setAddPage(!addPage)
      if(addPage){
        setButtonText("Add item")
      }
      else{
      setButtonText("to the room info")}
    }

  return (
    <div>
        {whatPageToShow()}
      <button onClick={changeAddPage}>{buttonText}</button>
      <Link to={"/myrooms"}><button>back to my rooms list</button></Link>
    </div>
  )
}
